public static <T extends Number> List<T> createList() {
    List<T> list = new ArrayList<T>();
    return list;
}

int num = 10;
Integer wrapper = new Integer(num);

List<T> list = createList();
list.add(num); // OK
list.add(wrapper); // Also OK
```

